const item = $input.first().json;

const now = new Date(item.now);
const eta = new Date(JSON.parse(item.eta)); 

const diffMs = now - eta;
const delayDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

return [
  {
    json: {
      ...item,
      delayDays
    }
  }
];

